function canReach(graph, start, target) {
  const visited = new Set();
  function go(node) {
    if (node === target) return true;
    visited.add(node);
    for (const nb of graph[node]) {
      if (!visited.has(nb) && go(nb)) return true;
    }
    return false;
  }
  return go(start);
}

