function floodFill(image, sr, sc, color) {
  const start = image[sr][sc];
  if (start === color) return image;
  const rows = image.length, cols = image[0].length;
  function fill(r, c) {
    if (r < 0 || r >= rows || c < 0 || c >= cols || image[r][c] !== start) return;
    image[r][c] = color;
    fill(r - 1, c);
    fill(r + 1, c);
    fill(r, c - 1);
    fill(r, c + 1);
  }
  fill(sr, sc);
  return image;
}
